function num(v) {
  if (v === null || v === undefined || v === "." || v === "") return null;
  const cleaned = String(v).replace("%", "").replace(",", ".").trim();
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
}

function getNode(name) {
  try {
    return $(name).first().json;
  } catch (error) {
    return null;
  }
}

function getNodeAll(name) {
  try {
    return $(name).all().map(item => item.json);
  } catch (error) {
    return [];
  }
}

function fredLatest(data) {
  const obs = data?.observations || [];
  const valid = obs.filter(o => num(o.value) !== null);
  const latest = num(valid[0]?.value);

  return {
    latest,
    d1: valid[1] && latest !== null ? latest - num(valid[1].value) : null,
    d5: valid[5] && latest !== null ? latest - num(valid[5].value) : null,
    d20: valid[20] && latest !== null ? latest - num(valid[20].value) : null,
    date: valid[0]?.date || null
  };
}

function fredPct(data) {
  const obs = data?.observations || [];
  const valid = obs.filter(o => num(o.value) !== null);
  const latest = num(valid[0]?.value);

  function pct(i) {
    const old = num(valid[i]?.value);
    if (latest === null || old === null || old === 0) return null;
    return ((latest - old) / old) * 100;
  }

  return {
    latest,
    d1: pct(1),
    d5: pct(5),
    d20: pct(20),
    date: valid[0]?.date || null
  };
}

function bundesbankCsvLatest(data) {
  const text = data?.data || "";
  const rows = String(text)
    .split("\n")
    .map(line => line.trim())
    .filter(line => /^\d{4}-\d{2}-\d{2};/.test(line))
    .map(line => {
      const parts = line.split(";");
      return { date: parts[0], value: num(parts[1]) };
    })
    .filter(row => row.value !== null)
    .reverse();

  const latest = rows[0]?.value ?? null;

  return {
    latest,
    d1: rows[1] && latest !== null ? latest - rows[1].value : null,
    d5: rows[5] && latest !== null ? latest - rows[5].value : null,
    d20: rows[20] && latest !== null ? latest - rows[20].value : null,
    date: rows[0]?.date || null
  };
}

function coinbasePrice(data) {
  return num(data?.data?.amount);
}

function alphaQuote(data) {
  const q = data?.["Global Quote"] || {};
  return {
    price: num(q["05. price"]),
    d1_pct: num(q["10. change percent"])
  };
}

function pctChange(current, old) {
  current = num(current);
  old = num(old);
  if (current === null || old === null || old === 0) return null;
  return ((current - old) / old) * 100;
}

function bps(v) {
  return v !== null && v !== undefined ? v * 100 : null;
}

function spread(a, b) {
  return a !== null && b !== null ? a - b : null;
}

function spreadD5(a, b) {
  if (a?.latest === null || b?.latest === null || a?.d5 === null || b?.d5 === null) return null;
  const spreadNow = a.latest - b.latest;
  const spread5dAgo = (a.latest - a.d5) - (b.latest - b.d5);
  return (spreadNow - spread5dAgo) * 100;
}

function rawText(data) {
  if (!data) return "";
  if (typeof data === "string") return data;
  return data.data || data.body || data.html || JSON.stringify(data);
}

function parseFearGreed(data) {
  return num(data?.data?.[0]?.value);
}

function parseCoinGeckoGlobal(data) {
  const d = data?.data || {};
  return {
    btc_dominance: num(d.market_cap_percentage?.btc),
    total_crypto_market_cap: num(d.total_market_cap?.usd)
  };
}

function parseFarsideNumber(v) {
  if (v === null || v === undefined) return null;
  let s = String(v).trim();
  if (!s || s === "-" || s === "–") return null;

  let negative = false;
  if (s.startsWith("(") && s.endsWith(")")) {
    negative = true;
    s = s.slice(1, -1);
  }

  s = s.replace(/,/g, "");
  const n = Number(s);
  if (!Number.isFinite(n)) return null;
  return negative ? -n : n;
}

function parseFarsideEtfFlows(data) {
  const text = rawText(data)
    .replace(/<[^>]*>/g, "\n")
    .replace(/&nbsp;/g, " ")
    .replace(/&#8211;/g, "-")
    .replace(/&amp;/g, "&");

  const tokens = text
    .split(/\n+/)
    .map(x => x.trim())
    .filter(Boolean);

  const rows = [];

  for (let i = 0; i < tokens.length; i++) {
    if (!/^\d{1,2}\s+[A-Za-z]{3}\s+20\d{2}$/.test(tokens[i])) continue;

    const date = tokens[i];
    const vals = [];

    for (let j = i + 1; j < tokens.length; j++) {
      if (/^\d{1,2}\s+[A-Za-z]{3}\s+20\d{2}$/.test(tokens[j])) break;
      const parsed = parseFarsideNumber(tokens[j]);
      if (parsed !== null) vals.push(parsed);
    }

    if (vals.length) {
      const totalUsdm = vals[vals.length - 1];
      rows.push({
        date,
        total_usdm: totalUsdm,
        total_usd: totalUsdm * 1000000
      });
    }
  }

  const valid = rows.filter(r => Number.isFinite(r.total_usd));

  return {
    latest: valid[0]?.total_usd ?? null,
    d5: valid.length ? valid.slice(0, 5).reduce((sum, r) => sum + r.total_usd, 0) : null,
    d20: valid.length ? valid.slice(0, 20).reduce((sum, r) => sum + r.total_usd, 0) : null,
    rows: valid.slice(0, 20)
  };
}

const now = new Date();
const today = now.toISOString().slice(0, 10);

const previousRows = getNodeAll("Supabase | Get Previous Market Snapshots")
  .filter(r => r.snapshot_date && r.run_time_et)
  .filter(r => r.snapshot_date < today)
  .sort((a, b) => new Date(b.run_time_et) - new Date(a.run_time_et));

const uniquePreviousRows = [];
const seenDates = new Set();

for (const row of previousRows) {
  if (!seenDates.has(row.snapshot_date)) {
    uniquePreviousRows.push(row);
    seenDates.add(row.snapshot_date);
  }
}

function historyPct(current, field, index) {
  const oldRow = uniquePreviousRows[index];
  return oldRow ? pctChange(current, oldRow[field]) : null;
}

