const recent   = $('HTTP Request | Eco Calendar Recent - Finnhub').first().json.economicCalendar;
const upcoming = $('HTTP Request | Eco Calendar Upcoming - Finnhub').first().json.economicCalendar;

// Tier-1 US indicators with sigma values for surprise normalisation
const TIER1 = {
  'Non Farm Payrolls':          { key: 'NFP',           sigma: 80 },
  'Average Hourly Earnings MoM':{ key: 'AHE_MOM',       sigma: 0.1 },
  'Unemployment Rate':          { key: 'UNEMPLOYMENT',  sigma: 0.15 },
  'Core Inflation Rate MoM':    { key: 'CORE_CPI_MOM',  sigma: 0.1 },
  'Inflation Rate MoM':         { key: 'CPI_MOM',       sigma: 0.15 },
  'ISM Manufacturing PMI':      { key: 'ISM_MFG',       sigma: 2.5 },
  'ISM Services PMI':           { key: 'ISM_SVCS',      sigma: 2.5 },
  'GDP Growth Rate QoQ Adv':    { key: 'GDP_ADV',       sigma: 0.5 },
  'ADP Employment Change':      { key: 'ADP',           sigma: 50 },
  'Initial Jobless Claims':     { key: 'JOBLESS_CLAIMS',sigma: 15 },
  'JOLTs Job Openings':         { key: 'JOLTS',         sigma: 0.3 }
};

// Filter recent US high/medium impact events with actuals
const recentUS = (recent || []).filter(e =>
  e.country === 'US' &&
  ['high','medium'].includes(e.impact) &&
  e.actual !== null
);

// Filter upcoming US high/medium impact events without actuals
const upcomingUS = (upcoming || []).filter(e =>
  e.country === 'US' &&
  ['high','medium'].includes(e.impact) &&
  e.actual === null
);

// Compute surprise scores for tier-1 recent prints
const surprises = [];
for (const event of recentUS) {
  const tier1 = TIER1[event.event];
  if (!tier1) continue;
  if (event.actual === null || event.estimate === null) continue;
  const surprise = (event.actual - event.estimate) / tier1.sigma;
  surprises.push({
    key:       tier1.key,
    event:     event.event,
    date:      event.time.split(' ')[0],
    actual:    event.actual,
    estimate:  event.estimate,
    surprise:  Math.round(surprise * 100) / 100,
    direction: surprise > 0 ? 'BEAT' : surprise < 0 ? 'MISS' : 'IN LINE'
  });
}

// Format upcoming calendar
const calendar = upcomingUS.map(e => ({
  event:    e.event,
  time:     e.time,
  estimate: e.estimate,
  impact:   e.impact
}));

// Format recent all US high/medium events (not just tier-1) for prompt context
const recentSummary = recentUS.slice(-20).map(e => ({
  event:    e.event,
  time:     e.time.split(' ')[0],
  actual:   e.actual,
  estimate: e.estimate,
  prev:     e.prev,
  impact:   e.impact
}));

return [{
  json: {
    surprises,
    calendar,
    recentSummary
  }
}];

const eco = $('Code | Process Eco Data').first().json;

const surprises = eco.surprises || [];

let score = 0;
const reasons = [];

for (const s of surprises) {
  if (s.direction === "BEAT") {
    score += 1;
    reasons.push(`${s.event} beat forecast`);
  }

  if (s.direction === "MISS") {
    score -= 1;
    reasons.push(`${s.event} missed forecast`);
  }
}

let fed_bias = "neutral";

if (score >= 2) fed_bias = "hawkish";
if (score <= -2) fed_bias = "dovish";

return [
  {
    json: {
      fed_bias,
      fed_bias_score: score,
      fed_bias_reasons: reasons.slice(0, 5)
    }
  }
];

function impactRank(impact) {
  const s = String(impact || '').toLowerCase();
  if (s.includes('high')) return 3;
  if (s.includes('medium')) return 2;
  if (s.includes('low')) return 1;
  return 0;
}

function priority(name) {
  const n = String(name || '').toLowerCase();

  if (n.includes('non farm') || n.includes('nfp')) return 100;
  if (n.includes('cpi') || n.includes('inflation')) return 98;
  if (n.includes('fomc') || n.includes('fed')) return 96;
  if (n.includes('ism')) return 94;
  if (n.includes('pmi')) return 90;
  if (n.includes('gdp')) return 88;
  if (n.includes('unemployment')) return 85;
  if (n.includes('average hourly')) return 82;
  if (n.includes('jobless')) return 78;
  if (n.includes('jolts')) return 75;
  if (n.includes('retail sales')) return 72;

  return 50;
}

function eventTime(e) {
  return `${e.event_date || ''} ${e.event_time_text || '00:00'}`;
}

const events = $input.all().map(i => i.json);

const completed = events
  .filter(e => e.actual !== null && e.actual !== undefined && e.actual !== '')
  .map(e => ({
    event: e.event_name,
    actual: e.actual,
    forecast: e.forecast,
    previous: e.previous,
    surprise: e.surprise_direction,
    usd_signal: e.currency_signal,
    surprise_score: e.surprise_score ?? null,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact),
    raw: e
  }))
  .sort((a, b) => {
    const timeDiff = new Date(eventTime(b.raw)) - new Date(eventTime(a.raw));
    if (timeDiff !== 0) return timeDiff;
    return b.priority - a.priority;
  });

const upcoming_us_events = events
  .filter(e => e.actual === null || e.actual === undefined || e.actual === '')
  .map(e => ({
    event: e.event_name,
    forecast: e.forecast,
