  if (n.includes('pmi')) return 90;
  if (n.includes('gdp')) return 88;
  if (n.includes('unemployment')) return 85;
  if (n.includes('average hourly')) return 82;
  if (n.includes('jobless')) return 78;
  if (n.includes('jolts')) return 75;
  if (n.includes('retail sales')) return 72;

  return 50;
}

function eventTime(e) {
  return `${e.event_date || ''} ${e.event_time_text || '00:00'}`;
}

const events = $input.all().map(i => i.json);

const completed = events
  .filter(e => e.actual !== null && e.actual !== undefined && e.actual !== '')
  .map(e => ({
    event: e.event_name,
    actual: e.actual,
    forecast: e.forecast,
    previous: e.previous,
    surprise: e.surprise_direction,
    usd_signal: e.currency_signal,
    surprise_score: e.surprise_score ?? null,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact),
    raw: e
  }))
  .sort((a, b) => {
    const timeDiff = new Date(eventTime(b.raw)) - new Date(eventTime(a.raw));
    if (timeDiff !== 0) return timeDiff;
    return b.priority - a.priority;
  });

const upcoming_us_events = events
  .filter(e => e.actual === null || e.actual === undefined || e.actual === '')
  .map(e => ({
    event: e.event_name,
    forecast: e.forecast,
    previous: e.previous,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact)
  }))
  .sort((a, b) => String(a.time || '').localeCompare(String(b.time || '')))
  .slice(0, 10);

const latest_us_event = completed[0] || null;

let fed_bias_score = 0;
const fed_bias_reasons = [];

for (const e of completed.slice(0, 8)) {
  const weight = e.impact_rank >= 3 ? 2 : 1;

  if (e.usd_signal === 'BULLISH') {
    fed_bias_score += weight;
    fed_bias_reasons.push(`${e.event} beat forecast`);
  }

  if (e.usd_signal === 'BEARISH') {
    fed_bias_score -= weight;
    fed_bias_reasons.push(`${e.event} missed forecast`);
  }
}

let fed_bias = 'neutral';
if (fed_bias_score >= 2) fed_bias = 'hawkish';
if (fed_bias_score <= -2) fed_bias = 'dovish';

return [{
  json: {
    latest_us_event,
    upcoming_us_events,
    fed_bias,
    fed_bias_score,
    fed_bias_reasons,
    recentUsSummary: completed,
    usCalendar: upcoming_us_events,
    source: 'economic_events',
    data_quality: {
      us_events_found: events.length,
      completed_us_events_found: completed.length,
      upcoming_us_events_found: upcoming_us_events.length
    }
  }
}];
